import{_ as t}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as i,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Auto Tagging","description":"","frontmatter":{},"headers":[],"relativePath":"fa/Other/auto-tagging.md","filePath":"fa/Other/auto-tagging.md","lastUpdated":1781962217000}'),o={name:"fa/Other/auto-tagging.md"};function l(n,a,g,c,p,r){return i(),s("div",null,[...a[0]||(a[0]=[d('<h1 id="auto-tagging" tabindex="-1">Auto Tagging <a class="header-anchor" href="#auto-tagging" aria-label="Permalink to &quot;Auto Tagging&quot;">​</a></h1><p>Auto tagging از این مسیر configure می‌شود:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>این قابلیت image tags را به‌صورت خودکار می‌سازد. این tags برای search، random image filtering، public gallery filtering و age-rating access control مفید هستند.</p><h2 id="auto-tagging-چه-کارهایی-می‌تواند-انجام-دهد" tabindex="-1">Auto Tagging چه کارهایی می‌تواند انجام دهد <a class="header-anchor" href="#auto-tagging-چه-کارهایی-می‌تواند-انجام-دهد" aria-label="Permalink to &quot;Auto Tagging چه کارهایی می‌تواند انجام دهد&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>ساخت content tags</td><td>tags مربوط به people، scenes، objects، art style و content visual مشابه را اضافه می‌کند.</td></tr><tr><td>ساخت character tags</td><td>برای anime images و illustrations کاربرد دارد.</td></tr><tr><td>افزودن orientation tags</td><td><code>landscape</code>، <code>portrait</code> یا <code>square</code> را اضافه می‌کند.</td></tr><tr><td>افزودن image rating</td><td>نتایج rating به‌شکل <code>G/S/Q/E</code> را برای general، sensitive، questionable یا explicit content ذخیره می‌کند.</td></tr><tr><td>auto-tag هنگام upload</td><td>images تازه upload شده خودکار وارد tagging flow می‌شوند.</td></tr><tr><td>Batch tagging</td><td>به images قدیمی در همه folders یا selected folders tags اضافه می‌کند.</td></tr></tbody></table><h2 id="ابتدا-چه-چیزی-لازم-است" tabindex="-1">ابتدا چه چیزی لازم است <a class="header-anchor" href="#ابتدا-چه-چیزی-لازم-است" aria-label="Permalink to &quot;ابتدا چه چیزی لازم است&quot;">​</a></h2><p>حداقل یک Hugging Face Space URL قابل دسترس آماده کنید.</p><p>روش پیشنهادی این است که Space مربوط به <code>wd-tagger</code> از SmilingWolf را داخل Hugging Face account خودتان duplicate کنید:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>می‌توانید موقتاً از public Space استفاده کنید، اما public Spaces بین کاربران زیادی مشترک هستند و ممکن است queue، کندی یا unavailable شدن داشته باشند. duplicated Space داخل account خودتان برای auto tagging طولانی‌مدت پایدارتر است.</p><h2 id="duplicate-کردن-space-smilingwolf" tabindex="-1">Duplicate کردن Space SmilingWolf <a class="header-anchor" href="#duplicate-کردن-space-smilingwolf" aria-label="Permalink to &quot;Duplicate کردن Space SmilingWolf&quot;">​</a></h2><ol><li>وارد Hugging Face شوید.</li><li><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code> را باز کنید.</li></ol><p><img src="'+t+`" alt="SmilingWolf public Space" loading="lazy"></p><ol start="3"><li>از گوشه بالا سمت راست منوی سه‌نقطه را بزنید.</li><li><code>Duplicate this Space</code> را انتخاب کنید.</li><li>نام پیش‌فرض Space را نگه دارید یا نام دلخواه بدهید، مثل <code>wd-tagger</code>.</li><li>visibility را <code>Public</code> بگذارید. Public Spaces برای call شدن توسط ImgBed ساده‌تر هستند.</li><li>برای شروع، default free hardware را نگه دارید. فقط وقتی queue واضحاً مشکل‌ساز شد upgrade کنید.</li><li>Space را create کنید و منتظر بمانید build تمام شود.</li></ol><p>پس از پایان build، صفحه Space خودتان را باز کنید. URL معمولاً شبیه این است:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>URL مرورگر را copy کنید و در <code>Space URLs</code> داخل ImgBed paste کنید.</p><h2 id="وارد-کردن-چند-space-url" tabindex="-1">وارد کردن چند Space URL <a class="header-anchor" href="#وارد-کردن-چند-space-url" aria-label="Permalink to &quot;وارد کردن چند Space URL&quot;">​</a></h2><p>در هر line یک Space URL وارد کنید.</p><p>نمونه‌ها:</p><table tabindex="0"><thead><tr><th>Value</th><th>Description</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>public Space مربوط به SmilingWolf. مناسب برای تست موقت.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>URL صفحه Space کپی‌شده.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>duplicated Space خودتان.</td></tr></tbody></table><p>می‌توانید چند URL وارد کنید. ImgBed چند Space را با هم استفاده می‌کند و این می‌تواند سرعت را بهتر کند.</p><p>اگر یکی از Spaceها موقتاً unavailable باشد، بقیه می‌توانند processing را ادامه دهند.</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Space URLs آماده‌شده را وارد کنید. حداقل یکی لازم است.</td></tr><tr><td>Target folder</td><td>برای همه folders خالی بگذارید. فقط وقتی directory خاصی می‌خواهید، folder انتخاب کنید.</td></tr><tr><td>Recognition model</td><td>پیش‌فرض <code>wd-swinv2-tagger-v3</code> را نگه دارید.</td></tr><tr><td>General tag threshold</td><td>مقدار پیش‌فرض برای بیشتر images مناسب است. مقدار کمتر tags بیشتری می‌دهد؛ مقدار بیشتر tags کمتری می‌دهد.</td></tr><tr><td>Character tag threshold</td><td>پیش‌فرض محافظه‌کارانه است و کمک می‌کند character tags اشتباه کمتر شود.</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>ابتدا off بگذارید. وقتی می‌خواهید model خودش تعداد tags را تعیین کند، on کنید.</td></tr><tr><td>Auto-tag on upload</td><td>اگر images جدید باید خودکار tag بگیرند، on کنید.</td></tr><tr><td>Start tagging</td><td>batch-tagging دستی برای images قدیمی.</td></tr></tbody></table><h2 id="مقادیر-شروع-پیشنهادی" tabindex="-1">مقادیر شروع پیشنهادی <a class="header-anchor" href="#مقادیر-شروع-پیشنهادی" aria-label="Permalink to &quot;مقادیر شروع پیشنهادی&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommended Value</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>ابتدا Off</td></tr><tr><td>Auto-tag on upload</td><td>در صورت نیاز Enable</td></tr></tbody></table><p>اگر tags خیلی زیاد است، general threshold را کمی بالا ببرید.</p><p>اگر tags خیلی کم است، general threshold را کمی پایین بیاورید.</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li><code>Space URLs</code> را پر کنید.</li><li>target folder انتخاب کنید.</li><li>start tagging را بزنید.</li><li>منتظر بمانید progress تمام شود.</li></ol><p>اگر target folder خالی باشد، ImgBed همه folders را process می‌کند.</p><p>Batch tagging برای images قدیمی بهتر است. برای images جدید، auto-tag on upload را enable کنید تا هر بار manual اجرا نکنید.</p><h2 id="auto-tag-هنگام-upload" tabindex="-1">Auto-Tag هنگام Upload <a class="header-anchor" href="#auto-tag-هنگام-upload" aria-label="Permalink to &quot;Auto-Tag هنگام Upload&quot;">​</a></h2><p>پس از enable شدن auto-tag on upload، images تازه upload شده خودکار <code>Space URLs</code> configured را call می‌کنند.</p><p>این حالت برای استفاده طولانی‌مدت مناسب است.</p><p>اگر Space در queue باشد، upload می‌تواند اول finish شود و tagging بعداً ادامه پیدا کند.</p><h2 id="کدام-images-پردازش-می‌شوند" tabindex="-1">کدام Images پردازش می‌شوند <a class="header-anchor" href="#کدام-images-پردازش-می‌شوند" aria-label="Permalink to &quot;کدام Images پردازش می‌شوند&quot;">​</a></h2><p>Auto tagging عمدتاً image files را process می‌کند.</p><p>images که tags، orientation، rating، width و height کامل دارند، skip می‌شوند تا Space calls غیرضروری انجام نشود.</p><p>ImgBed تا حد ممکن فقط اطلاعات missing را پر می‌کند. مثلاً اگر فقط orientation missing باشد، سعی می‌کند بدون call کردن full content tag flow، orientation را اضافه کند.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="چرا-space-خودم-را-duplicate-کنم؟" tabindex="-1">چرا Space خودم را Duplicate کنم؟ <a class="header-anchor" href="#چرا-space-خودم-را-duplicate-کنم؟" aria-label="Permalink to &quot;چرا Space خودم را Duplicate کنم؟&quot;">​</a></h3><p>Public Spaces بین کاربران زیادی مشترک هستند. duplicated Space شما معمولاً فقط توسط ImgBed site شما استفاده می‌شود، بنابراین اغلب سریع‌تر و قابل‌اعتمادتر است.</p><h3 id="space-مدام-starting-up-می‌شود" tabindex="-1">Space مدام Starting Up می‌شود <a class="header-anchor" href="#space-مدام-starting-up-می‌شود" aria-label="Permalink to &quot;Space مدام Starting Up می‌شود&quot;">​</a></h3><p>بعد از اولین creation یا پس از idle طولانی، Space ممکن است برای start شدن زمان لازم داشته باشد.</p><p>اول صفحه Space خودتان را باز کنید. وقتی توانست image را عادی recognize کند، به ImgBed برگردید و tagging را شروع کنید.</p><h3 id="space-url-را-چطور-copy-کنم؟" tabindex="-1">Space URL را چطور Copy کنم؟ <a class="header-anchor" href="#space-url-را-چطور-copy-کنم؟" aria-label="Permalink to &quot;Space URL را چطور Copy کنم؟&quot;">​</a></h3><p>صفحه Hugging Face Space خود را باز کنید و address مرورگر را copy کنید.</p><p>نمونه‌ها:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="می‌توانم-چند-space-اضافه-کنم؟" tabindex="-1">می‌توانم چند Space اضافه کنم؟ <a class="header-anchor" href="#می‌توانم-چند-space-اضافه-کنم؟" aria-label="Permalink to &quot;می‌توانم چند Space اضافه کنم؟&quot;">​</a></h3><p>بله. در هر line یک Space URL وارد کنید.</p><p>چند Space با هم images را process می‌کنند و وقتی images زیاد دارید مفید است.</p><h3 id="چرا-tags-انگلیسی-هستند؟" tabindex="-1">چرا Tags انگلیسی هستند؟ <a class="header-anchor" href="#چرا-tags-انگلیسی-هستند؟" aria-label="Permalink to &quot;چرا Tags انگلیسی هستند؟&quot;">​</a></h3><p>مدل‌های SmilingWolf خروجی tags را انگلیسی می‌دهند. این مورد طبیعی است.</p><p>tags بیشتر برای search، filtering، random image API و public gallery filters استفاده می‌شوند.</p><h3 id="rating-tags-برای-چیست؟" tabindex="-1">Rating Tags برای چیست؟ <a class="header-anchor" href="#rating-tags-برای-چیست؟" aria-label="Permalink to &quot;Rating Tags برای چیست؟&quot;">​</a></h3><p>rating results همراه access mode در Security Settings کار می‌کنند.</p><p>مثلاً وقتی visitor access بر اساس age rating محدود باشد، public browsing و random image features طبق همان rules images را filter می‌کنند.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>وارد Hugging Face شوید</span></span>
<span class="line"><span>-&gt; SmilingWolf/wd-tagger را باز کنید</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; منتظر build شدن Space بمانید</span></span>
<span class="line"><span>-&gt; Space URL خودتان را copy کنید</span></span>
<span class="line"><span>-&gt; Space URLs را در ImgBed وارد کنید</span></span>
<span class="line"><span>-&gt; model و thresholds را انتخاب کنید</span></span>
<span class="line"><span>-&gt; Start tagging یا auto-tag on upload را enable کنید</span></span></code></pre></div>`,63)])])}const m=e(o,[["render",l]]);export{b as __pageData,m as default};
